module multiplexer(
    input [1:0] select,
    input [3:0] obf_in,
    output reg out);always @(*) begin
    case (select)
        2'd0: out = obf_in[0];
        2'd1: out = obf_in[1];
        2'd2: out = obf_in[2];
        2'd3: out = obf_in[3];
        default: out = 1'b0;
    endcase
end
endmodule
